export const ActiveKey = () => {
  const [activeKey, setActiveKey] = useState<string>('tab2');
  return (
    <div>
      <Radio.Group value={activeKey} onChange={v => setActiveKey(v as string)}>
        <Radio.Button value="tab1">tab1</Radio.Button>
        <Radio.Button value="tab2">tab2</Radio.Button>
        <Radio.Button value="tab3">tab3</Radio.Button>
      </Radio.Group>
      <div style={{ padding: 10 }}>
        <Tabs activeKey={activeKey}>
          <TabPane tab="tab1" key="tab1">
            <div>TabPane content1</div>
          </TabPane>
          <TabPane tab="tab2" key="tab2">
            <div>
              <p>TabPane content2.</p>
              <p>TabPane content2.</p>
              <p>TabPane content2.</p>
              <p>TabPane content2.</p>
            </div>
          </TabPane>
          <TabPane tab="tab3" key="tab3">
            <div>TabPane content3</div>
          </TabPane>
        </Tabs>
      </div>
    </div>
  );
};

