export const ShowMore = () => {
  const [w, setW] = useState(400);
  const [size, setSize] = useState<DefaultSizeType>('medium');
  const [type, setType] = useState<TabsType>('line');

  return (
    <Space style={{ width: '100%' }} direction="vertical" size="large">
      <div style={{ width: '50%' }}>
        <span>宽度:</span>
        <Slider value={w} onChange={setW} step={100} min={400} max={1000} />
      </div>
      <Space size="large" align="center">
        <div>
          <span style={{ marginRight: 8 }}>Size: </span>
          <Radio.Group value={size} onChange={(v: any) => setSize(v)}>
            <Radio.Button value="large">Large</Radio.Button>
            <Radio.Button value="medium">Medium</Radio.Button>
            <Radio.Button value="small">Small</Radio.Button>
          </Radio.Group>
        </div>
        <div>
          <span style={{ marginRight: 8 }}>Type: </span>
          <Radio.Group value={type} onChange={(v: any) => setType(v)}>
            <Radio.Button value="line">Line</Radio.Button>
            <Radio.Button value="card">Card</Radio.Button>
            <Radio.Button value="tag">Tag</Radio.Button>
          </Radio.Group>
        </div>
      </Space>
      <Tabs style={{ width: w }} size={size} type={type}>
        {[...Array.from({ length: 15 }, (v, i) => i)].map((i, index) => (
          <TabPane key={String(index)} tab={`标签 ${index + 1}`} disabled={index === 12}>
            <div>TabPane content {index + 1} </div>
          </TabPane>
        ))}
      </Tabs>
    </Space>
  );
};

export const MaxCount = () => {
  const [count, setCount] = useState(8);
  const [size, setSize] = useState<DefaultSizeType>('medium');
  const [type, setType] = useState<TabsType>('line');

  return (
    <Space style={{ width: '100%' }} direction="vertical" size="large">
      <div style={{ width: '50%' }}>
        <span>最大展示数量:</span>
        <Slider value={count} onChange={setCount} step={1} min={5} max={15} />
      </div>
      <Space size="large" align="center">
        <div>
          <span style={{ marginRight: 8 }}>Size: </span>
          <Radio.Group value={size} onChange={(v: any) => setSize(v)}>
            <Radio.Button value="large">Large</Radio.Button>
            <Radio.Button value="medium">Medium</Radio.Button>
            <Radio.Button value="small">Small</Radio.Button>
          </Radio.Group>
        </div>
        <div>
          <span style={{ marginRight: 8 }}>Type: </span>
          <Radio.Group value={type} onChange={(v: any) => setType(v)}>
            <Radio.Button value="line">Line</Radio.Button>
            <Radio.Button value="card">Card</Radio.Button>
            <Radio.Button value="tag">Tag</Radio.Button>
          </Radio.Group>
        </div>
      </Space>
      <Tabs maxCount={count} size={size} type={type}>
        {[...Array.from({ length: 15 }, (v, i) => i)].map((i, index) => (
          <TabPane key={String(index)} tab={`标签 ${index + 1}`} disabled={index === 12}>
            <div>TabPane content {index + 1} </div>
          </TabPane>
        ))}
      </Tabs>
    </Space>
  );
};

