export const Stretch = () => {
  const paneStyle = {
    height: '100%',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  };
  return (
    <Tabs style={{ height: 400 }}>
      <TabPane tab="tab1" style={paneStyle}>
        <Illustration image={<EmptyNegativeError />} description="Error" />
      </TabPane>
    </Tabs>
  );
};

export const Scrollable = () => {
  const TAB_COUNT = 20;
  const [scrollable, setScrollable] = React.useState(true);
  const [activeKey, setActiveKey] = React.useState('tab1');
  return (
    <div style={{ maxWidth: 500 }}>
      <Checkbox checked={scrollable} onCheckChange={v => setScrollable(v)}>
        Tabs Scrollable
      </Checkbox>
      <Button onClick={() => setActiveKey('tab9')}>切换到 Tab9</Button>
      <Tabs scrollable={scrollable} onChange={key => setActiveKey(key)} activeKey={activeKey}>
        {new Array(TAB_COUNT).fill('').map((_, index) => (
          <TabPane
            key={`tab${index}`}
            tab={
              <span>
                <ContactsOutlined /> Tab {index}
              </span>
            }
          >
            Content of Tab Panel {index}
          </TabPane>
        ))}
      </Tabs>
    </div>
  );
};
